Patch Set 12:

also, would you mind the following change:

@@ -1324,7 +1324,7 @@ is_dm_flakey_dev() {
 dm_flakey_supported() {
        local facet=$1

-       do_facet $facet "modprobe dm-flakey &&
+       do_facet $facet "modprobe dm-flakey;
                         $DMSETUP targets | grep -q flakey" &> /dev/null
 }


so it can work with statically-built dm support.
